sql:
SELECT COUNT(*)
FROM salespeople
WHERE performance_rating = 'good';

SELECT commission_rate 
FROM salespeople
WHERE name = 'Jane Smith';

SELECT name, email 
FROM customers
WHERE annual_income > (SELECT AVG(annual_income) FROM customers);

external_knowledge:
- "marketplaces" refers to dealerships;
- "crossed the threshold of thirty thousand dollars" means priced at or below $30,000;
- "models that have traveled through the doors" metaphorically refers to the vehicles being present in multiple dealerships' inventories.

- "fading treasures" refers to vehicles that have high mileage;
- "in motion more than 30,000 times" refers to vehicles with mileage greater than 30,000;
- "auctioned in the lands across the British Isles" refers to vehicles sold in UK locations;
- "hues of navy or scarlet" refers to the vehicle colors 'blue' and 'red';
- "monetary value" refers to the sale price.
